final:
module RefModule( input [31:0] Multiplexer_Instruction, 
							 input [31:0] Jump_Instruction,
							 input Jump_Control,
							 output [31:0] New_PC
							 );reg [31:0] final_sig;

	always @(*) begin
		case (Jump_Control) 
			0: final_sig <= Multiplexer_Instruction;
			1: final_sig <= Jump_Instruction;
		endcase 
	end

	assign New_PC = final_sig;
endmodule
